import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // sorted desc: 6,5,4,3,2,1 => 2nd largest = 5
        assertEquals(5, new Solution().kthLargest(new int[]{3,2,1,5,6,4}, 2));
    }

    @Test
    void longerArray() {
        // sorted desc: 6,5,5,4,3,3,2,2,1 => 4th largest = 4
        assertEquals(4, new Solution().kthLargest(new int[]{3,2,3,1,2,4,5,5,6}, 4));
    }

    @Test
    void kEqualsOne() {
        // largest element
        assertEquals(20, new Solution().kthLargest(new int[]{7,10,4,3,20,15}, 1));
    }

    @Test
    void kEqualsLength() {
        // smallest element (kth = last in desc order)
        assertEquals(1, new Solution().kthLargest(new int[]{2,1}, 2));
    }

    @Test
    void singleElement() {
        assertEquals(42, new Solution().kthLargest(new int[]{42}, 1));
    }

    @Test
    void allDuplicates() {
        // all same value — every kth-largest is the same value
        assertEquals(5, new Solution().kthLargest(new int[]{5,5,5,5}, 2));
    }

    @Test
    void thirdLargest() {
        // sorted desc: 20,15,10,7,4,3 => 3rd = 10
        assertEquals(10, new Solution().kthLargest(new int[]{7,10,4,3,20,15}, 3));
    }
}
